arguments.command:
$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2022-06-28'; 'Content-Type' = 'application/json' }
$body = @{
  page_size = 100
  filter = @{
    property = 'Status'
    status = @{ does_not_equal = 'Done' }
  }
} | ConvertTo-Json -Depth 10
$data = Invoke-RestMethod -Method Post -Uri 'https://api.notion.com/v1/databases/32f0a0b1-97cc-81a8-9443-df3f85f2ffc7/query' -Headers $headers -Body $body
$data.results | ForEach-Object {
  $p=$_.properties
  [pscustomobject]@{
    Task = ($p.'Task name'.title.plain_text -join '')
    Owner = ($p.Owner.rich_text.plain_text -join '')
    Status = $p.Status.status.name
    Area = ($p.Area.rich_text.plain_text -join '')
    NeedsGustavo = $p.'Needs Gustavo'.checkbox
    NextCheck = if($p.'Next check'.date){$p.'Next check'.date.start}else{''}
    LastEdited = $_.last_edited_time
    NextStep = ($p.'Next step'.rich_text.plain_text -join '')
    Evidence = ($p.'Evidence / brief'.rich_text.plain_text -join '')
    Notes = ($p.Notes.rich_text.plain_text -join '')
  }
} | ConvertTo-Json -Depth 5

